import {
  ChangeDetectionStrategy,
  Component,
  effect,
  forwardRef,
  InjectionToken,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { codeToHtml, type BundledLanguage, type ShikiTransformer } from 'shiki';

/**
 * Highlights `code` for both light and dark themes (github-light-default
 * and github-dark-default — same as rx-ai). Optionally prepends line
 * numbers via a Shiki transformer.
 */
export async function highlightCode(
  code: string,
  language: BundledLanguage,
  showLineNumbers = false,
): Promise<[string, string]> {
  const transformers: ShikiTransformer[] = showLineNumbers
    ? [lineNumberTransformer]
    : [];

  return Promise.all([
    codeToHtml(code, {
      lang: language,
      theme: 'github-light-default',
      transformers,
    }),
    codeToHtml(code, {
      lang: language,
      theme: 'github-dark-default',
      transformers,
    }),
  ]) as Promise<[string, string]>;
}

const lineNumberTransformer: ShikiTransformer = {
  name: 'line-numbers',
  line(node, line) {
    node.children.unshift({
      type: 'element',
      tagName: 'span',
      properties: {
        className: [
          'inline-block',
          'min-w-10',
          'mr-4',
          'text-right',
          'select-none',
          'text-muted-foreground',
        ],
      },
      children: [{ type: 'text', value: String(line) }],
    });
  },
};

/**
 * CodeBlock — Shiki-highlighted code container.
 *
 * Mirrors React `CodeBlock`. Renders both light and dark snapshots and
 * shows the right one via Tailwind's `dark:` variants — same approach as
 * rx-ai. Exposes the raw `code` via DI so `<code-block-copy-button>`
 * stays decoupled.
 */
export interface CodeBlockState {
  code: () => string;
}

export const CODE_BLOCK = new InjectionToken<CodeBlockState>('CodeBlockState');

@Component({
  selector: 'code-block',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="relative">
      <div
        class="overflow-auto dark:hidden [&>pre]:m-0 [&>pre]:bg-background! [&>pre]:p-4 [&>pre]:text-foreground! [&>pre]:text-sm [&_code]:font-mono [&_code]:text-sm"
        [innerHTML]="lightHtml()"
      ></div>
      <div
        class="hidden overflow-auto dark:block [&>pre]:m-0 [&>pre]:bg-background! [&>pre]:p-4 [&>pre]:text-foreground! [&>pre]:text-sm [&_code]:font-mono [&_code]:text-sm"
        [innerHTML]="darkHtml()"
      ></div>
      <div class="absolute top-2 right-2 flex items-center gap-2">
        <ng-content />
      </div>
    </div>
  `,
  host: {
    class:
      'group relative w-full overflow-hidden rounded-md border bg-background text-foreground block',
  },
  providers: [
    { provide: CODE_BLOCK, useExisting: forwardRef(() => CodeBlock) },
  ],
})
export class CodeBlock implements CodeBlockState {
  readonly code = input.required<string>();
  readonly language = input.required<BundledLanguage>();
  readonly showLineNumbers = input<boolean>(false);

  protected readonly lightHtml = signal<string>('');
  protected readonly darkHtml = signal<string>('');

  constructor() {
    let cancelled = false;
    effect((onCleanup) => {
      cancelled = false;
      onCleanup(() => {
        cancelled = true;
      });
      const c = this.code();
      const lang = this.language();
      const lines = this.showLineNumbers();
      highlightCode(c, lang, lines)
        .then(([light, dark]) => {
          if (cancelled) return;
          this.lightHtml.set(light);
          this.darkHtml.set(dark);
        })
        .catch((err) => {
          // Fallback to plain pre on highlight failure.
          if (cancelled) return;
          const fallback = `<pre><code>${escapeHtml(c)}</code></pre>`;
          this.lightHtml.set(fallback);
          this.darkHtml.set(fallback);
          console.warn('[ng-ai] CodeBlock highlight failed', err);
        });
    });
  }
}

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

import {
  ChangeDetectionStrategy,
  Component,
  inject,
  input,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

import { CODE_BLOCK } from './code-block';

/**
 * CodeBlockCopyButton — copy-to-clipboard icon button.
 *
 * Mirrors React `CodeBlockCopyButton`. Reads the code from the parent
 * `<code-block>` via DI; emits `(copied)` on success, `(errored)` on
 * failure.
 */
@Component({
  selector: 'code-block-copy-button',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="buttonClass"
      (click)="copy()"
      aria-label="Copy code"
    >
      <ng-content>
        @if (isCopied()) {
          <svg
            width="14"
            height="14"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            aria-hidden="true"
          >
            <path d="M20 6 9 17l-5-5" />
          </svg>
        } @else {
          <svg
            width="14"
            height="14"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            aria-hidden="true"
          >
            <rect width="14" height="14" x="8" y="8" rx="2" ry="2" />
            <path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2" />
          </svg>
        }
      </ng-content>
    </button>
  `,
})
export class CodeBlockCopyButton {
  readonly timeout = input<number>(2000);

  readonly copied = output<void>();
  readonly errored = output<Error>();

  private readonly host = inject(CODE_BLOCK);
  protected readonly isCopied = signal(false);

  protected readonly buttonClass = cn(
    'shrink-0 inline-flex size-7 items-center justify-center rounded-md text-foreground/70 hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
  );

  protected async copy(): Promise<void> {
    if (typeof window === 'undefined' || !navigator?.clipboard?.writeText) {
      this.errored.emit(new Error('Clipboard API not available'));
      return;
    }
    try {
      await navigator.clipboard.writeText(this.host.code());
      this.isCopied.set(true);
      this.copied.emit();
      setTimeout(() => this.isCopied.set(false), this.timeout());
    } catch (err) {
      this.errored.emit(err as Error);
    }
  }
}

export { CodeBlock, CODE_BLOCK, highlightCode } from './code-block';
export type { CodeBlockState } from './code-block';
export { CodeBlockCopyButton } from './code-block-copy-button';
